public class SecureCipher {
    private static final String ECB_MODE_STRING = "AES/ECB/PKCS5Padding";
    public void encrypt(byte[] data, SecretKey key) throws Exception {
        Cipher c = Cipher.getInstance("AES/GCM/NoPadding");
        c.init(Cipher.ENCRYPT_MODE, key);
    }
}

public class BadIV {
    public void encrypt(byte[] data, SecretKey key) throws Exception {
        Cipher c = Cipher.getInstance("AES/CBC/PKCS5Padding");
        byte[] staticIv = "1234567890123456".getBytes();
        c.init(Cipher.ENCRYPT_MODE, key, new IvParameterSpec(staticIv));
    }
}

public class BadRandom {
    public void genKey() {
        java.util.Random rnd = new java.util.Random();
        byte[] key = new byte[16];
        rnd.nextBytes(key);
        SecretKeySpec spec = new SecretKeySpec(key, "AES");
    }
}

public class GoodKDF {
    public SecretKey derive(char[] pass, byte[] salt) throws Exception {
        PBEKeySpec spec = new PBEKeySpec(pass, salt, 100000, 256);
        SecretKeyFactory f = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
        return f.generateSecret(spec);
    }
}
